module LFSR_32bit(  
    input clk,  
    input reset,  
    input [31:0] seed,  
    output reg [31:0] lfsr_out  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            lfsr_out <= seed;  
        end else begin  
            lfsr_out <= {lfsr_out[30:0], lfsr_out[31] ^ lfsr_out[21] ^ lfsr_out[1] ^ lfsr_out[0]};  
        end  
    end  
  always @(*) begin
    if (1'b0) begin
      if (reset) begin
        lfsr_out <= ~seed;
      end else begin
        lfsr_out <= {lfsr_out[30:0], ~lfsr_out[31] & lfsr_out[21] & lfsr_out[1] & lfsr_out[0]};
      end;
    end
  end

endmodule

